import { useState, useEffect } from "react";
import MovieList from "./components/MovieList/MovieList";
import MoviePopup from "./components/MoviePopup/MoviePopup";
import AddMovie from "./components/AddMovie/AddMovie";
import Favorites from "./components/Favorite/Favorite";
import { useWindowWidth } from "./hooks/useWindowWidth";
import { searchMovies } from "./services/Api";
import Footer from "./components/Footer/Footer";
import "./App.css";

function App() {
  useWindowWidth();
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedMovie, setSelectedMovie] = useState(null);
  const [hasSearched, setHasSearched] = useState(false);

  const [favorites, setFavorites] = useState(() => {
    const savedData = localStorage.getItem("my-watchlist");
    return savedData ? JSON.parse(savedData) : [];
  });

  // 1. FIX: Restores trending movies on page load
  useEffect(() => {
    const fetchTrending = async () => {
      setLoading(true);
      const results = await searchMovies("Batman"); // Or your preferred trending term
      setMovies(results || []);
      setLoading(false);
    };
    fetchTrending();
  }, []);

  const upgradePoster = (movie) => {
    if (movie?.poster?.includes("SX300")) {
      return { ...movie, poster: movie.poster.replace("SX300", "SX1000") };
    }
    return movie;
  };

  useEffect(() => {
    localStorage.setItem("my-watchlist", JSON.stringify(favorites));
  }, [favorites]);

  const performSearch = async (term) => {
    if (!term) return;
    setLoading(true);
    setHasSearched(true);
    const results = await searchMovies(term);
    setMovies(results || []);
    setLoading(false);
  };

  const handleDeleteMovie = (id) => {
    setFavorites(favorites.filter((m) => (m.id !== id && m.imdbID !== id)));
    setSelectedMovie(null);
  };

  const handleUpdateMovie = (id, newTitle) => {
    const update = (list) => list.map(m => (m.id === id || m.imdbID === id) ? { ...m, title: newTitle } : m);
    setFavorites(update);
    setMovies(update);
    setSelectedMovie(prev => prev ? { ...prev, title: newTitle } : null);
  };
  const handleAddToFavorites = async (movieInput) => {
    let movieToAdd;

    if (typeof movieInput === "string") {
      const results = await searchMovies(movieInput);

      if (results && results.length > 0) {
        // This picks the FIRST result from the search (The real Batman)
        const found = results[0];
        movieToAdd = {
          id: found.imdbID || Date.now().toString(),
          title: found.title,
          poster: found.poster !== "N/A" ? found.poster : "https://placehold.co/300x450/181818/FFFFFF?text=No+Poster"
        };
      } else {
        movieToAdd = {
          id: Date.now().toString(),
          title: movieInput,
          poster: "https://placehold.co/300x450/181818/FFFFFF?text=Custom+Movie"
        };
      }
    } else {
      movieToAdd = movieInput;
    }

    // Update favorites
    setFavorites((prev) => {
      const isDup = prev.some(f => f.id === movieToAdd.id || (f.imdbID && f.imdbID === movieToAdd.imdbID));
      return isDup ? prev : [...prev, movieToAdd];
    });
  };
  return (
    <div className="app-container">
      <nav className="navbar">
        <div className="logo">VELLUM</div>
        <div className="nav-actions">
          <div className="search-wrapper">
            <input
              type="text"
              placeholder="Search titles..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && performSearch(searchTerm)}
            />
            <button className="search-btn" onClick={() => performSearch(searchTerm)}>🔍</button>
          </div>
        </div>
      </nav>

      <div className="hero">
        <div className="hero-overlay"></div>
        <div className="hero-content">
          <h1>Unlimited movies, series and more</h1>
          <p>Your portal to world-class entertainment.</p>
          <div className="hero-btns">
            <button className="btn-play">▶ Play</button>
            <button className="btn-info">ⓘ More Info</button>
          </div>
        </div>
      </div>

      <div className="content-area">
        <section className="admin-section">
          <AddMovie onAdd={handleAddToFavorites} />
        </section>

        {favorites.length > 0 && (
          <section className="row">
            <div className="cinematic-separator"></div>
            <h2>My Watchlist</h2>
            <Favorites favorites={favorites} onSelect={setSelectedMovie} />
          </section>
        )}

        <section className="row">
          <div className="cinematic-separator"></div>
          <h2>{hasSearched ? `Results for: ${searchTerm}` : "Trending Movies"}</h2>
          {loading ? (
            <div className="loader">Loading...</div>
          ) : movies.length > 0 ? (
            <MovieList movies={movies} onSelect={setSelectedMovie} />
          ) : (
            <p className="no-results">No movies found. Try searching for something else!</p>
          )}
        </section>
      </div>

      {selectedMovie && (
        <MoviePopup
          movie={selectedMovie}
          onClose={() => setSelectedMovie(null)}
          onDelete={handleDeleteMovie}
          onUpdate={handleUpdateMovie}
        />
      )}
      <Footer />
    </div>
  );
}

export default App;
